/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fir_master` (
  `fir_id` int NOT NULL AUTO_INCREMENT,
  `fir_number` varchar(30) NOT NULL,
  `station_code` varchar(20) NOT NULL,
  `date_filed` date NOT NULL,
  `time_filed` time NOT NULL,
  `case_type` enum('theft','robbery','assault','murder','fraud','cybercrime','missing_person','vehicle_theft','drug_offense','domestic_violence','other') NOT NULL,
  `incident_date` date DEFAULT NULL,
  `incident_time` time DEFAULT NULL,
  `incident_location` varchar(200) DEFAULT NULL,
  `incident_lat` decimal(10,8) DEFAULT NULL,
  `incident_lng` decimal(11,8) DEFAULT NULL,
  `description` text,
  `status` enum('open','under_investigation','closed','chargesheeted') DEFAULT 'open',
  `investigating_officer_id` int DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`fir_id`),
  UNIQUE KEY `fir_number` (`fir_number`),
  KEY `investigating_officer_id` (`investigating_officer_id`),
  KEY `idx_fir_case_type` (`case_type`),
  KEY `idx_fir_status` (`status`),
  KEY `idx_fir_date` (`date_filed`),
  CONSTRAINT `fir_master_ibfk_1` FOREIGN KEY (`investigating_officer_id`) REFERENCES `officers` (`officer_id`)
) ENGINE=InnoDB AUTO_INCREMENT=221 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

